import { execFileSync } from "node:child_process";
import { parseArgs } from "node:util";
import { sourceRoot, workers, workerConfigPath } from "./deploy-configuration.mjs";

const {
  values: { "deploy-only": deployOnly, "dry-run": dryRun },
} = parseArgs({
  args: process.argv.slice(2),
  options: {
    "deploy-only": {
      type: "boolean",
      default: false,
    },
    "dry-run": {
      type: "boolean",
      default: false,
    },
  },
  strict: true,
});

if (dryRun && deployOnly) {
  console.error("--dry-run and --deploy-only cannot be used together.");
  process.exit(1);
}

const wranglerEnvironment = {
  ...process.env,
  WRANGLER_WRITE_LOGS: process.env.WRANGLER_WRITE_LOGS ?? "false",
};

if (!deployOnly) {
  for (const worker of workers) {
    dryRunWorker(worker, wranglerEnvironment);
  }
}

if (dryRun) {
  process.exit(0);
}

for (const worker of workers) {
  deployWorker(worker, wranglerEnvironment);
}

function deployWorker(worker, wranglerEnvironment) {
  runWrangler(["deploy", "--strict", "--config", workerConfigPath(worker)], wranglerEnvironment);
}

function dryRunWorker(worker, wranglerEnvironment) {
  runWrangler(
    ["deploy", "--dry-run", "--strict", "--config", workerConfigPath(worker)],
    wranglerEnvironment,
  );
}

function runWrangler(wranglerArguments, wranglerEnvironment) {
  execFileSync("pnpm", ["-C", sourceRoot, "exec", "wrangler", ...wranglerArguments], {
    env: wranglerEnvironment,
    stdio: "inherit",
  });
}

